func planLabel(plan apiclient.Entitlements) string {
	if string(plan.Plan) == "pro" {
		return "Pro"
	}
	return "Free"
}

func watchQuota(entitlements apiclient.Entitlements) string {
	if entitlements.WatchLimit < 0 {
		return fmt.Sprintf("%d active · unlimited", entitlements.ActiveWatches)
	}
	return fmt.Sprintf("%d of %d active watches", entitlements.ActiveWatches, entitlements.WatchLimit)
}

func watchDeleteAction(id string) string {
	return "/watches/" + id + "/delete"
}

func watchShareAction(id string) string {
	return "/watches/" + id + "/share"
}

func inboundHeadline(inbound *apiclient.InboundAircraft) string {
	if inbound == nil {
		return ""
	}
	parts := make([]string, 0, 3)
	if inbound.Registration != "" {
		parts = append(parts, inbound.Registration)
	}
	if inbound.FlightNumber != "" {
		parts = append(parts, inbound.FlightNumber)
	}
	if inbound.OriginIATA != "" && inbound.DestinationIATA != "" {
		parts = append(parts, inbound.OriginIATA+" → "+inbound.DestinationIATA)
	}
	if len(parts) == 0 {
		return "Inbound aircraft tracking"
	}
	out := parts[0]
	for i := 1; i < len(parts); i++ {
		out += " · " + parts[i]
	}
	return out
}

func watchSubtitle(item apiclient.Watch) string {
	if item.Flight != nil && item.Flight.Airline != "" {
		return item.Flight.Airline + " · updated " + relativeTime(item.UpdatedAt)
	}
	return "Watching · updated " + relativeTime(item.UpdatedAt)
}

func routeLabel(flight *apiclient.Flight) string {
	if flight == nil {
		return "Route pending"
	}
	if flight.DepartureIATA == "" && flight.ArrivalIATA == "" {
		return "Route pending"
	}
	dep := flight.DepartureIATA
	arr := flight.ArrivalIATA
	if dep == "" {
		dep = "???"
	}
	if arr == "" {
		arr = "???"
	}
	return dep + " → " + arr
}

func gateLabel(terminal, gate string) string {
	parts := make([]string, 0, 2)
	if terminal != "" {
		parts = append(parts, "Terminal "+terminal)
	}
	if gate != "" {
		parts = append(parts, "Gate "+gate)
	}
	if len(parts) == 0 {
		return "Gate pending"
	}
	if len(parts) == 1 {
		return parts[0]
	}
	return parts[0] + " · " + parts[1]
}

func baggageLabel(baggage string) string {
	if baggage == "" {
		return "Baggage pending"
	}
	return "Baggage " + baggage
}

func delayLabel(minutes *int) string {
	if minutes == nil || *minutes == 0 {
		return "On time signal"
	}
	return fmt.Sprintf("+%d min delay", *minutes)
}

func timeLabel(preferred, fallback time.Time) string {
	if !preferred.IsZero() {
		return preferred.Local().Format("15:04")
	}
	if !fallback.IsZero() {
		return fallback.Local().Format("15:04")
	}
	return "Time pending"
}

func relativeTime(value time.Time) string {
	if value.IsZero() {
		return "just now"
	}
	delta := time.Since(value)
	if delta < time.Minute {
		return "just now"
	}
	if delta < time.Hour {
		return fmt.Sprintf("%d min ago", int(delta.Minutes()))
	}
	return value.Local().Format("15:04")
}

